INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('northwood', '2026-04-22 04:05:37.543746', NULL, NULL, NULL, NULL, 0.037, NULL, NULL, 0.0, 68.0, 75.0, '["lodJQ9yhhuI", "4G89kNeLjNM", "OcrZoj7p1V4", "pvb2y-q8-c8", "5tu2lcRB-RU", "1sKUs9DxK7I", "boT5DROWr0Q", "MZ_ZFTJJ9X0", "w9M-tKdSUYc"]', '[{"id": "Ugw_QwjGyXF1MwbxkYB4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-09-21T03:58:39Z", "parent_id": null, "video_id": "pvb2y-q8-c8"}, {"id": "Ugx7J4ApIRFQ9ve10F54AaABAg", "text": "======\nFull Channel:   https://bit.ly/3NXecX3\n======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-10-17T05:42:33Z", "parent_id": null, "video_id": "1sKUs9DxK7I"}, {"id": "UgxEzJNEdnCyA4AaCMJ4AaABAg", "text": "11:14 The house where Janelle Cruz was killed by the Golden State Killer RIP", "author": "@JesusGarcia-kl3rf", "like_count": 0, "published_at": "2026-02-16T21:35:45Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx-HS5Gi1lF2f8oodB4AaABAg", "text": "Thanks for the amazing information. From UK London", "author": "@jdxaofficial", "like_count": 1, "published_at": "2025-12-03T20:12:52Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgztpdqR7Fa8IVIC-894AaABAg", "text": "Anyone looking for a new or newer built home in Irvine, especially in the newer neighborhoods, you better be prepared to pay north of $2.0MM for an average size home.  Considering you will be assessed property taxes at the market value of the home along with two HOAs, even if you have $1.0MM to put as down payment, your monthly bill for all of the above will still be a boat load ! ! !\n\nSo a professional couple pulling in $400K/yr probably can swing this neighborhood. \n\nTraffic has beome a nightmare and people are driving like there is no tomorrow. With all the foreigners coming here and not know the traffic laws, you better have eyes on the back of your head!\n\nI spoke with an officer from the Irvine PD about the traffic and he said there isn''t much they can do unless there is an incident. So until someone smashes into your vehicle, don''t look for help from the Irvine PD ! ! !\n\nLastly, this is a master planned community and Irivne being a DEI community, they have painted huge portions of the roadway for bicycles ! ! !  This encroaches on roadways for normal traffic!  I never ever see any bicycles on these marked off portion fo the roads but that''s Irvine putting taxpayers'' money to waste!", "author": "@LWRC", "like_count": 1, "published_at": "2024-08-26T23:49:04Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgxLYOC0IqIKn8mIfVx4AaABAg", "text": "Gr\u00fcne Welle (Green Wave Traffic lights) like germany", "author": "@dr.mirano", "like_count": 0, "published_at": "2023-06-08T04:29:16Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "UgzE9hZpLHws9Wo6U854AaABAg", "text": "Thank you for being the spokespersons for irvine", "author": "@afterburner5560", "like_count": 0, "published_at": "2023-05-28T06:44:32Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg", "text": "Nice!  When I am in the market for a condo, I will call you. Are there condo\u2019s that aren\u2019t HOA\u2019s in HB or Costa Mesa?", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-05-27T21:25:18Z", "parent_id": null, "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg.9qEFM1FzH719qEHV-OcIY5", "text": "HI Kalei ! \nThere aren''t any condos that I''m aware of that have no HOAs.  The reason being is that condos have shared walls, fences, etc.  The HOA dues can definitely vary from one community to the next.  When you are ready to reach out, we can go over all of different aspects of the various HOAs, including their HOA dues.", "author": "@runbamrun", "like_count": 1, "published_at": "2023-05-27T21:43:59Z", "parent_id": "Ugx71uFCZwca1OhOVIl4AaABAg", "video_id": "boT5DROWr0Q"}, {"id": "Ugx71uFCZwca1OhOVIl4AaABAg.9qEFM1FzH719qEHye9laNE", "text": "@runbamrun , I need prices to go down before I could afford a house.", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-05-27T21:48:10Z", "parent_id": "Ugx71uFCZwca1OhOVIl4AaABAg", "video_id": "boT5DROWr0Q"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('costa-mesa-border', '2026-04-22 04:06:33.254336', NULL, NULL, NULL, NULL, 0.527, NULL, NULL, 0.0, 75.0, 82.0, '["YmfLYoVM5FM", "R2zJ73ccgfk", "skWMGGqdP68", "WrvFY8PDqoA", "FMSCZ-gYfPE", "VhvlsJunOUQ", "aMoiKj7tEPI", "LzyeK1zb9_4", "jS5F_g_esjI", "9jdBAgf77nw"]', '[{"id": "UgxCWUT9f8PCtBGp4H54AaABAg", "text": "I didn''t see a shark attack her,and I''m glad I didn''t. I was praying \ud83d\ude1e\ud83d\ude4f", "author": "@IsayswhatIsays_91", "like_count": 0, "published_at": "2026-04-09T19:20:32Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxaA7s5drIkpnhwqKB4AaABAg", "text": "silly waste of your time and mine\ud83e\udd2c\ud83e\udd2f\u2757\ufe0f", "author": "@giglambert8787", "like_count": 0, "published_at": "2026-04-02T19:45:08Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxjcyJnm-xD9_TS2Pt4AaABAg", "text": "Shark!!! Maybe a beaver attack with a full moon????\ud83d\ude0a\ud83d\ude0a\ud83d\ude0a\ud83d\ude0a", "author": "@j.e.g2321", "like_count": 0, "published_at": "2026-03-29T04:38:07Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "Ugx0czskOGIW_jkr5Nl4AaABAg", "text": "Looks like shes pi$$ing", "author": "@briandonahue3663", "like_count": 0, "published_at": "2026-03-28T19:04:41Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgxOWlpXvQlt1fAduxx4AaABAg", "text": "Don''t take the sharpy find a leg or he won''t stop the headstones from brote", "author": "@mis-u2y", "like_count": 0, "published_at": "2026-03-27T23:24:37Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgzJm_d-piXAm-Mpft14AaABAg", "text": "That hungry butt must have ate the shark. It was devouring the swimsuit for dessert.", "author": "@cobrakaiX", "like_count": 0, "published_at": "2026-03-27T14:53:45Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgwR9yqwX3IEZR02eSp4AaABAg", "text": "What shark? The seagull?", "author": "@Bobbyboy-i3z", "like_count": 0, "published_at": "2026-03-18T19:03:17Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgyrMS77lojHk-CH_a14AaABAg", "text": "The shark ate your baby...\nAnd now you are wearing her swimsuit.", "author": "@diasdesmo1730", "like_count": 0, "published_at": "2026-03-07T17:47:32Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgzGfjqJRWeF1YdCb0h4AaABAg", "text": "Two years later, the clickbait still works!", "author": "@Guu1969", "like_count": 0, "published_at": "2026-03-04T19:49:28Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgyFAr0gQe2iibCaEPV4AaABAg", "text": "B.S.", "author": "@THENEONARCADE21", "like_count": 0, "published_at": "2026-02-22T05:14:50Z", "parent_id": null, "video_id": "R2zJ73ccgfk"}, {"id": "UgziEb6HUgu6gZnCchJ4AaABAg", "text": "The fastest one \ud83c\udfc3\u200d\u2642\ufe0f", "author": "@gavinkirkham7765", "like_count": 0, "published_at": "2026-04-22T03:03:26Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "UgzkcSrwM4VhSF_HVOd4AaABAg", "text": "Dangerously no calves \ud83d\ude05", "author": "@RandyGee-n2h", "like_count": 0, "published_at": "2026-04-21T23:06:55Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "Ugx4C3bE4v9kUuOAInt4AaABAg", "text": "Elephant vs donkey", "author": "@yourfriend5359", "like_count": 0, "published_at": "2026-04-21T16:53:05Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "Ugx0WMIgBKKR4kln7k94AaABAg", "text": "they should be fighting in jocks like real MEN", "author": "@BerserkerZerkwise", "like_count": 0, "published_at": "2026-04-19T15:58:23Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "UgzIgXQSthV_nEXrxbx4AaABAg", "text": "Funny part is top heavy Timmy probably can\u2019t even remotely fight and the second you leg kick him hes shattering", "author": "@BigxMotion22", "like_count": 0, "published_at": "2026-04-18T15:48:10Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "UgzOww0dviDoU6NuSwt4AaABAg", "text": "How dem chicken legs hold dat tank upright?", "author": "@bmid3", "like_count": 0, "published_at": "2026-04-18T02:34:25Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "UgxU_CueDX_tCbTuRsl4AaABAg", "text": "GORILLA MAGUILA!!!!", "author": "@jcns448", "like_count": 0, "published_at": "2026-04-15T17:48:06Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "UgwuiPpH8nAcwJeV3XN4AaABAg", "text": "chicken legs wont win", "author": "@davidfannan3505", "like_count": 0, "published_at": "2026-04-15T13:59:34Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "Ugz-ue3jH7xYQYgPaxZ4AaABAg", "text": "leg day? nope", "author": "@janossztanity5781", "like_count": 0, "published_at": "2026-04-14T21:38:54Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "UgyzAv4--kzblYjDsIx4AaABAg", "text": "Match Sticks legs \ud83d\ude02", "author": "@CaptainKedah", "like_count": 0, "published_at": "2026-04-12T01:54:11Z", "parent_id": null, "video_id": "skWMGGqdP68"}, {"id": "Ugxq0nvhV951PP8t_6t4AaABAg", "text": "Yesterday, Glimmerito tried to shoot a 30-year-old woman \ud83d\udc69 after trying to replace my music \ud83c\udfb6 therapist after I attacked and nearly put an end to her.", "author": "@emily91303", "like_count": 0, "published_at": "2023-08-03T09:19:09Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgzVSt4kU9HLIexEAM94AaABAg", "text": "If you wouldnt of broke the law coming here illegally in the first place you wouldnt be dead. \ud83d\ude02\ud83d\ude02\ud83d\ude02\ud83d\ude02.. try and play victim.", "author": "@travisengland1368", "like_count": 0, "published_at": "2023-07-17T00:46:45Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "Ugw_t3DfLVwLJKBV5SN4AaABAg", "text": "Well maybe if they didnt hit a car with a family in it and then drive away they wouldnt of got shot.. good job lee. You da man Stay up g..", "author": "@travisengland1368", "like_count": 0, "published_at": "2023-07-17T00:45:04Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgxdFaVdHwU-w4qjI5x4AaABAg", "text": "Export this criminal activity back to Mexico", "author": "@OLD-GUY-99", "like_count": 0, "published_at": "2023-07-05T01:24:34Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgwjzbiuxhUPAJ13u9Z4AaABAg", "text": "Foo struck out big time.... No more Woman, vacations \ud83c\udfdd\ufe0f,  steak \ud83e\udd69, shrimp \ud83c\udf64, ocean \ud83c\udf0a,  .... Was it really worth it????? Nothing but showers \ud83d\udebf with naked men all around u for the rest of ur young life...... Gotta think \ud83e\udd14 before u react.... It''s hard, but it''s a must!!!!", "author": "@simonrangel9522", "like_count": 0, "published_at": "2023-02-22T04:28:24Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgzanZrq_cAX8LQMPOx4AaABAg", "text": "More to the story for sure.", "author": "@mikelabree", "like_count": 0, "published_at": "2023-01-31T03:17:23Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgwO0S1vIVsrTNbN4bx4AaABAg", "text": "Rest in peace of my Dad''s friend he''s been a wonderful person and we pray God that he''s going to be okay this is the fake this is real this is what''s my dad''s friend", "author": "@abandoned_dead", "like_count": 1, "published_at": "2022-12-30T02:36:05Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgzPeKb6lylDrKCosOh4AaABAg", "text": "Hmmmm, just a guess, black?", "author": "@peridoteyes3728", "like_count": 0, "published_at": "2022-12-11T23:12:03Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "UgyQZ0PEQhP-en1-wSp4AaABAg", "text": "I drive a truck I\u2019m always ready to defend if some punk tries to pull out a gun on me.", "author": "@ezpe3865", "like_count": 0, "published_at": "2022-12-11T02:19:41Z", "parent_id": null, "video_id": "9jdBAgf77nw"}, {"id": "Ugw-OCIiL7potSaPLS94AaABAg", "text": "Why didn\u2019t you guys show the shooters picture \ud83e\udd26", "author": "@DirtyDrifter", "like_count": 0, "published_at": "2022-12-11T01:17:04Z", "parent_id": null, "video_id": "9jdBAgf77nw"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('great-park', '2026-04-22 04:07:39.804003', NULL, NULL, NULL, NULL, 0.0, NULL, NULL, 0.0, 62.0, 69.0, '["wbW7ATTytGw", "BCi20EOGAOw", "fgnmivjjM5Y", "mzUJlvPVEIU", "5tu2lcRB-RU", "7iLH9vzL2Qo", "srt2NuMUmpk", "6YgL4JN1bYw"]', '[{"id": "UgxuakSkH-9yNOFW2pt4AaABAg", "text": "As of today, pretty much 1 M or above in GP.", "author": "@jennifer12366", "like_count": 1, "published_at": "2025-05-29T22:15:02Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgxuakSkH-9yNOFW2pt4AaABAg.AIikijwDg1JAIjO4EPAvkz", "text": "Thanks for watching our video! It''s Irvine so that sums up the market...However, if looking for a new home, builders are being very aggressive with offering incentives on upgrades and financing. Still not inexpensive though!", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-05-30T04:07:38Z", "parent_id": "UgxuakSkH-9yNOFW2pt4AaABAg", "video_id": "wbW7ATTytGw"}, {"id": "UgyQEfxCrn8nV_4oMPV4AaABAg", "text": "Like like like like like like", "author": "@Yuriy_Beskrovniy", "like_count": 1, "published_at": "2023-03-24T16:56:35Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgyQEfxCrn8nV_4oMPV4AaABAg.9ndyiur43ex9ne31aT96tR", "text": "Thanks Thanks Thanks! Really appreciate your watching our videos.", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2023-03-24T17:42:57Z", "parent_id": "UgyQEfxCrn8nV_4oMPV4AaABAg", "video_id": "wbW7ATTytGw"}, {"id": "Ugy-WHOhohgo7cO0omh4AaABAg", "text": "======\nFull Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\n=======\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 \n\ud83d\udcf1Call or text:  949-285-1207   \n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\n\ud83d\udcc5Schedule a Zoom Call So That We Can Meet \"In-Person\":  https://calendly.com/living-in-irvine-ca/30min?month=2022-10", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-08-21T03:57:15Z", "parent_id": null, "video_id": "wbW7ATTytGw"}, {"id": "UgyS-5UXKpCisyHaCB14AaABAg", "text": "The Ducks train there (Irvine) but all Home games ( where the play) are at the Honda Center. Nice video.", "author": "@sikhlion5325", "like_count": 0, "published_at": "2026-01-21T02:05:18Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgwK87YbpQYZA1botKV4AaABAg", "text": "WOW", "author": "@kennaylul", "like_count": 1, "published_at": "2025-04-06T23:56:14Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgxdHUhUk6rXtNb2iRF4AaABAg", "text": "Hi There,\r\nHow are you?\r\nI watched your videos, and your video quality is great! However, your videos are not properly optimized for SEO. Your SEO score is quite poor, which is why your channel is not growing organically.\r\nSEO stands for Search Engine Optimization. I\u2019m sure you understand that to get more views, subscribers, and comments, your videos need to rank higher on YouTube. Proper SEO, such as selecting low-competition keywords, can help your channel rank at the top.\r\nThank you", "author": "@Mrjosef-m6i", "like_count": 1, "published_at": "2025-04-06T18:02:47Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgzF1rBsIfGC1fxKAQB4AaABAg", "text": "\u2764\u2764\u2764\u2764\u2764\u2764\u2764\u2764\u2764\u2764", "author": "@ThienPham-bj9ki", "like_count": 1, "published_at": "2025-04-05T22:54:15Z", "parent_id": null, "video_id": "BCi20EOGAOw"}, {"id": "UgybCfVKLxz429TY-Gd4AaABAg", "text": "When is it gonna be made?", "author": "@Kyson-p8c", "like_count": 0, "published_at": "2026-03-11T19:16:52Z", "parent_id": null, "video_id": "fgnmivjjM5Y"}, {"id": "UgxoJCWe8ALUYknsCbh4AaABAg", "text": "is it true that Great Park is was the former El Toro Marine Corps Air Station which is a toxic Superfund site?? i want to move here but this is a huge community concern if it''s true", "author": "@sp-ff1pt", "like_count": 0, "published_at": "2025-12-06T18:09:20Z", "parent_id": null, "video_id": "mzUJlvPVEIU"}, {"id": "UgxrRvhijxyfxiQ5F2J4AaABAg", "text": "If you work from home try Thailand or Vietnam. You get a better apartment with an ocean view free daily cleaning service for $850/month", "author": "@hash_value", "like_count": 0, "published_at": "2026-04-05T13:02:57Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "text": "I hate the extraneous noises of apartment living. That''s why I bought a house.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:07:15Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg.AU9leOfMix5AUNRnLyJwxT", "text": "Good for you!!!! House privacy is the best tbh", "author": "@theamericanexplorer", "like_count": 0, "published_at": "2026-03-15T12:34:20Z", "parent_id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "Ugx_SBkM3eJCHRl0F2l4AaABAg", "text": "Don\u2019t do it find another place another state", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:17:28Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg", "text": "Welcome to California. Welcome to Orange County the Irvine development company building huge compounds to shuffling people. That is their goal. Heavy taxes have a government and you will get nothing.", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:12:24Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg.APFXOwGwUjaAU9qUUTiJCP", "text": "Lady, you don''t know what you''re talking about. \n1) Renters don''t pay property taxes on their apartment. \n2) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \n3) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \n4) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:49:27Z", "parent_id": "UgzskPqRyemqVIE5NnR4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgwBv8B2eGpjpqi2XNt4AaABAg", "text": "Just one big heaping mound of regret why would you don\u2019t do it?", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:10:58Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "text": "I hope you love taxes and heavy government. Enjoy", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:56Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg.APFWlsu6i1DAU9rD00IBtZ", "text": "Lady, you don''t know what you''re talking about. \r\n1) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \r\n2) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \r\n3) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \r\nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.\r\n\r\nThe reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:55:48Z", "parent_id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg", "text": "Why would you buy a property in California?\ud83d\ude02 What an absolute joke", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:30Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rTCJbL30", "text": "Lady, the reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:58:01Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rnxx2Wqd", "text": "rockyrodes5 She doesn''t care about facts. She''s just a Republican with a hard need to vent against California, the 4th largest economy in the world.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T06:00:59Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('oak-creek', '2026-04-22 04:08:44.460239', NULL, NULL, NULL, NULL, 0.031, NULL, NULL, 0.0, 68.0, 75.0, '["OIobezbcUh0", "F08HtkKlBLQ", "8HkRHp8ocOo", "wFh8YI9xEQw", "f-4c3kNBm3M", "-_0Nfgut_N0", "9OlRx5tSQnU", "urwBJvYOtx0"]', '[{"id": "UgwfWwo1oOdVQN0bc5x4AaABAg", "text": "Hello! I am a student from EDUBUS. EDUBUS is an educational center for students seeking admission to private schools. I am currently attending a class about this redevelopment. We will attend a City Council Meeting to try to persuade them to keep the Oak Creek Golf Course. As one of the scripters (potentially the speaker), I would dearly appreciate some opinions on this redevelopment.", "author": "@faltrx", "like_count": 0, "published_at": "2025-08-06T03:58:48Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgzcoU55MQ42fz6YB_F4AaABAg", "text": "Surely you have enough traffic already.", "author": "@chris7987", "like_count": 0, "published_at": "2025-07-09T03:52:14Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgyZ5IB8m3r0Rs02Lz14AaABAg", "text": "More expensive housing? Irvine is already for rich people \ud83d\ude02", "author": "@Chato829", "like_count": 0, "published_at": "2025-07-07T23:21:13Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgwHVeYpEdHRmxYDnEB4AaABAg", "text": "You know how cities work. If they want it, they''ll take it.", "author": "@slanphere4", "like_count": 2, "published_at": "2025-07-07T10:31:26Z", "parent_id": null, "video_id": "f-4c3kNBm3M"}, {"id": "UgyQnpL6mnGR_ALppbx4AaABAg", "text": "Watching this video gave me hope in golf.", "author": "@user-vr6yw3tp7p", "like_count": 1, "published_at": "2024-01-24T20:50:40Z", "parent_id": null, "video_id": "-_0Nfgut_N0"}, {"id": "Ugwt3SYuFnQZMbGQ9A54AaABAg", "text": "I actually like the commentary over the top with some moments during the round shared.  Good perspective.  Also, you''re in my league so happy to see the coaching in the cart! lol  Keep up the great content.", "author": "@majen66", "like_count": 2, "published_at": "2023-11-15T23:51:30Z", "parent_id": null, "video_id": "-_0Nfgut_N0"}, {"id": "Ugwt3SYuFnQZMbGQ9A54AaABAg.9x9OoJdOIVB9x9Z8bfn9BV", "text": "I really appreciate feedback like this. I''m still trying to figure out my \"style\" of video and it''s really helpful to hear what viewers like as I try different things out. Thanks so much!! Appreciate your watch and your comments.", "author": "@golfwithjames", "like_count": 0, "published_at": "2023-11-16T01:21:47Z", "parent_id": "Ugwt3SYuFnQZMbGQ9A54AaABAg", "video_id": "-_0Nfgut_N0"}, {"id": "Ugy9_flrg-gyVFzPZoB4AaABAg", "text": "Really enjoying your content!!  Keep em coming!", "author": "@Grunt21Tennessee", "like_count": 1, "published_at": "2023-10-02T13:13:32Z", "parent_id": null, "video_id": "-_0Nfgut_N0"}, {"id": "Ugy9_flrg-gyVFzPZoB4AaABAg.9vMxpGfA1df9vN1RAO0dL8", "text": "Thanks!! I''ll have the back 9 up this week as well!", "author": "@golfwithjames", "like_count": 1, "published_at": "2023-10-02T13:53:48Z", "parent_id": "Ugy9_flrg-gyVFzPZoB4AaABAg", "video_id": "-_0Nfgut_N0"}, {"id": "Ugye8cE6OdxceBq8nOl4AaABAg", "text": "Dear Sir,\r\nI''m a big fan of your channel and I regularly follow your videos. I have expertise in YouTube SEO and digital marketing. After reviewing your channel, I identified 10 possible reasons why your subscriber and view count are not improving as expected.\r\nIf you''d like, I can offer you a free channel audit and even create a professional audio for your video intro. Please reply, Sir\n\n\u2014I''d love to assist you in growing your channel.", "author": "@saidulvm", "like_count": 0, "published_at": "2025-04-14T04:07:55Z", "parent_id": null, "video_id": "urwBJvYOtx0"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('irvine-spectrum', '2026-04-22 04:01:54.941469', NULL, NULL, NULL, NULL, 0.137, NULL, NULL, 0.0, 75.0, 82.0, '["VlihgtoWi8E", "npR2EkyPXbo", "IFri3Ejn7AM", "iyp1Pk4k6is", "7dKmgDgUuhU", "PE429i3aCdY", "vtkr-PT4Bcs", "tNQt4HTwLbo", "LjRl4aEWnSo", "srt2NuMUmpk"]', '[{"id": "UgwEJXVJdrAg9Zo9bxd4AaABAg", "text": "\u2705 You might enjoy watching my video on Crystal Cove: https://youtu.be/n6cIfZeH4AI\r\n\u2705 Or Laguna Beach: https://youtu.be/Ek55xJ2md5E", "author": "@YellowProductions", "like_count": 4, "published_at": "2024-12-14T04:46:18Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxOihsJzcDHaYWeinN4AaABAg", "text": "I love arcade games at Dave and busters! \u2764\ud83d\ude0aalita", "author": "@AlitaKnight", "like_count": 0, "published_at": "2026-04-14T22:20:20Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgwwZRKq-Rulm0RqrUN4AaABAg", "text": "Habit is better than In-N-Out", "author": "@papagen00", "like_count": 0, "published_at": "2025-12-29T22:17:06Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxqP3veKEKdUXzDqS14AaABAg", "text": "Irvine company is the worst", "author": "@negrobeard", "like_count": 0, "published_at": "2025-12-28T06:10:21Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "Ugx_CoW_4zp_7Ou7rb94AaABAg", "text": "Thank you Sir \u2764\u2764\u2764\u2764", "author": "@kimyoung3484", "like_count": 2, "published_at": "2025-08-11T20:30:28Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgyWImsnajBNXf6SmEN4AaABAg", "text": "This is not. BIG mall as stated, it\u2019s okay. Beautiful spot but not much shopping options as an indoor mall.", "author": "@rcsc824sc8", "like_count": 0, "published_at": "2025-06-29T16:07:55Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "Ugx1DKwXJkO4yGFvpL54AaABAg", "text": "Very Wonderful Shopping Center Video!!! I Love the Fountains!!!! F+L, Corey", "author": "@coreycoyle9548", "like_count": 4, "published_at": "2025-06-21T17:03:23Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "Ugxh91Pu-6Byrk6-wDp4AaABAg", "text": "Be careful of that Cheesecake location. Got food poisoning there.", "author": "@Jenn_Jenn-w5i", "like_count": 0, "published_at": "2025-05-31T19:08:37Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxqQlnWff1lzcQ1wk94AaABAg", "text": "I was from the Orange County area. I lived thier for 11 years and the Irvine Spectrum was one of my favorite spots to go shopping.", "author": "@matteocarlini27", "like_count": 4, "published_at": "2025-05-12T20:08:43Z", "parent_id": null, "video_id": "npR2EkyPXbo"}, {"id": "UgxqQlnWff1lzcQ1wk94AaABAg.AI1kkhc7uNIAIfahZXgjn-", "text": "I''m from London and I want to move to California why did you move out if I may ask", "author": "@Offline.e.e.e", "like_count": 0, "published_at": "2025-05-28T16:49:46Z", "parent_id": "UgxqQlnWff1lzcQ1wk94AaABAg", "video_id": "npR2EkyPXbo"}, {"id": "UgxqQlnWff1lzcQ1wk94AaABAg.AI1kkhc7uNIAIg9cNlGdgp", "text": "@Offline.e.e.eI am still in California, I moved from Southern California because my mom got a job in Northern California", "author": "@matteocarlini27", "like_count": 0, "published_at": "2025-05-28T22:03:38Z", "parent_id": "UgxqQlnWff1lzcQ1wk94AaABAg", "video_id": "npR2EkyPXbo"}, {"id": "UgwW5OF380uo3zMl3Ex4AaABAg", "text": "Is it worth it?", "author": "@usairmx", "like_count": 0, "published_at": "2026-04-06T11:30:06Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzZW-eWn69kLxK4I4Z4AaABAg", "text": "Irvine...sleepy place...with the roar of freeways at a number of neighborhoods.", "author": "@marcmorin2129", "like_count": 0, "published_at": "2026-03-20T03:56:59Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugwlr4My4cvpfEYcyyF4AaABAg", "text": "That sounds about right or a little less...you can afford a 1 bed room high rise. Older 2 bd condos 900k to start. Great Park just Mello and HOA set you back 1400 to -1600 per month ...Any house in OC decent safe starts at 1.1mm", "author": "@sallycoo5527", "like_count": 0, "published_at": "2026-02-09T04:08:50Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugzyc_zneQ_H7l8GZsd4AaABAg", "text": "I live down the street and yes most apartment homes are over a million", "author": "@dg8676", "like_count": 1, "published_at": "2026-01-02T15:30:23Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgyXzoaz9Ie2z9d7WVd4AaABAg", "text": "I grew up in Irvine and still live here. With that statistic you just said I would say the majority of people that live here now are considered low income. They have built so many more apartments here now.", "author": "@wali82", "like_count": 0, "published_at": "2025-12-24T16:09:09Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzXttZ4Tz_S4mML3-N4AaABAg", "text": "That\u2019s fair, suspicious and interesting at the same time.", "author": "@ashleymoore_12_99", "like_count": 0, "published_at": "2025-11-10T22:49:38Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgwHUXQjrjb23ztHH2R4AaABAg", "text": "And also extremely boring and cookie cutter homes.", "author": "@alfonsonuno", "like_count": 0, "published_at": "2025-09-15T00:23:49Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "Ugwcqo5nsoQK9kXD06h4AaABAg", "text": "Quote the source ?", "author": "@Gary-v7j", "like_count": 0, "published_at": "2025-09-07T18:48:26Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzY-nqUFf_L5mV9LX54AaABAg", "text": "I\u2019m a cyber hacker and stole 1.7 million in 2022 and have made money along the way Irvine is rich and very nice to live if you got money", "author": "@booogiee1258", "like_count": 1, "published_at": "2025-06-22T20:36:29Z", "parent_id": null, "video_id": "IFri3Ejn7AM"}, {"id": "UgzY-nqUFf_L5mV9LX54AaABAg.AJgNWuK3SaYAOBpC42KwgU", "text": "Right\u2026.", "author": "@alexc08", "like_count": 0, "published_at": "2025-10-12T21:08:19Z", "parent_id": "UgzY-nqUFf_L5mV9LX54AaABAg", "video_id": "IFri3Ejn7AM"}, {"id": "UgzjZKy3nd3vSRBz8HV4AaABAg", "text": "*\ua9c1  Buen \ud83d\udc4c\ud83d\udc4c v\u00eddeo \ud83d\ude09 \ud83d\udc4d  \ua9c2*", "author": "@DUHOVED_FOR_RELAX", "like_count": 2, "published_at": "2023-01-30T06:02:36Z", "parent_id": null, "video_id": "iyp1Pk4k6is"}, {"id": "UgzjZKy3nd3vSRBz8HV4AaABAg.9lVKkf9EP4u9lVsnIy4Fdd", "text": "Thanks for watching", "author": "@slowsteadywalk", "like_count": 1, "published_at": "2023-01-30T11:08:47Z", "parent_id": "UgzjZKy3nd3vSRBz8HV4AaABAg", "video_id": "iyp1Pk4k6is"}, {"id": "Ugxr6fxWr8DfOXTYmQ54AaABAg", "text": "Beautiful place to walk around at night enjoy and thanks for sharing", "author": "@JefPersonalVideos", "like_count": 2, "published_at": "2023-01-27T14:54:11Z", "parent_id": null, "video_id": "iyp1Pk4k6is"}, {"id": "Ugxr6fxWr8DfOXTYmQ54AaABAg.9lOZCSncKpF9lVsmCRBEUN", "text": "Thanks for watching", "author": "@slowsteadywalk", "like_count": 1, "published_at": "2023-01-30T11:08:38Z", "parent_id": "Ugxr6fxWr8DfOXTYmQ54AaABAg", "video_id": "iyp1Pk4k6is"}, {"id": "Ugz7l40YP-WOxEVmDqF4AaABAg", "text": "My son is 17, Northwood high school. GPA over 3.5. He''s had a good high school experience. He''s not taking all AP classes and not getting tudors. Yes, if you want over a 4.0 there''s more work involved. But going to school in Irvine doesn''t require crazy amounts of work and tudors if you don''t want to go to an Ivy league school. You can still get into fine schools, haha.", "author": "@ChrisRivera-lz3lo", "like_count": 0, "published_at": "2026-04-16T21:06:47Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgyRk3mrSkDvvRbOrW94AaABAg", "text": "I raised all 3 of my kids in Woodbridge, spent half of my 72 years there. No complaints", "author": "@robertkendall1037", "like_count": 0, "published_at": "2026-03-20T16:57:45Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "Ugwep9dq5yI_FgL7TkV4AaABAg", "text": "A family I am close to with two young children moved from Pasadena to Irvine for work. They liked Pasadena, but they have grown to like Irvine. Their rent is higher in Irvine, but they are in a nice place that is not 100 years old.", "author": "@prrosenkrantz", "like_count": 0, "published_at": "2026-02-15T07:36:33Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgyYa8UWhXGsOUlkMpx4AaABAg", "text": "\ud83e\udd14....mmm Irvine way hotter??? Somebody wants to sell more houses closer to the beach...", "author": "@Franciscodelporto", "like_count": 0, "published_at": "2026-01-12T03:22:49Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "Ugwre5ef-NVNhqbLa1N4AaABAg", "text": "It takes time to understand Irvine.  But once you live there after a year you realize why it was built the way it is with shopping centers facing inward to prevent crime, pedestrians, and homeless.  And how it was built with 3 to 4 lane throughways to improve traffic and minimize slowing by moving entrances to shopping centers to inner streets.  And of course the master planned communities designed to mix apartments, condos and SFHs to provide diversity within each village.  Then there\u2019s the massive amount of land dedicated to parks and biking.  Irvine is intentionally the anti-city designed to improve the quality of family life.", "author": "@ap774", "like_count": 0, "published_at": "2025-11-19T15:58:27Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgybuXEX8V9EEdCu6IV4AaABAg", "text": "Irvine is so over built and the traffic is horrible. Most of the shopping centers are so crowded it can be hard to find a parking spot. It was a great place 45 years ago but no more!", "author": "@MikeB-in1nd", "like_count": 2, "published_at": "2025-08-25T23:26:09Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgybuXEX8V9EEdCu6IV4AaABAg.AMGToWgnO7lAVaacHdhsbx", "text": "they didnt have internet 45 years ago so it cant have been that good, may as well say 500 years ago for all it relates to anyone today", "author": "@drinkwater9891", "like_count": 0, "published_at": "2026-04-14T21:00:58Z", "parent_id": "UgybuXEX8V9EEdCu6IV4AaABAg", "video_id": "PE429i3aCdY"}, {"id": "UgyyuQcAzQAHsyIDxpZ4AaABAg", "text": "I''m grew up in Irvine as a child of the 80s. It was a great place to grow up.", "author": "@peterphan227", "like_count": 2, "published_at": "2025-08-08T13:09:24Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgwY3FTtcMUxy-Pk3wx4AaABAg", "text": "Irvine is for people with zero imagination. It\u2019s like loving franchise food. I grew up there and lived there in the mid seventies stayed until I turned thirty. So if you\u2019re uptight with control issues you will definitely feel at home in Irvine.", "author": "@plugnut4713", "like_count": 0, "published_at": "2025-07-29T13:37:37Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "Ugz5EHubbTRv6gEzgcN4AaABAg", "text": "Get to the point! 4 minutes in and rambling on and on", "author": "@safewayguy", "like_count": 8, "published_at": "2025-07-22T12:44:04Z", "parent_id": null, "video_id": "PE429i3aCdY"}, {"id": "UgwNALVh4T8Q4-1nXyd4AaABAg", "text": "The yogurt and pretzels something something also the escape gameee i played all of em (my favorite\u2019s prison break and gold rush) with my stupid cousins and my brother and my mom about 2 years ago", "author": "@AngelaLiu-z4j", "like_count": 0, "published_at": "2025-11-26T07:37:54Z", "parent_id": null, "video_id": "vtkr-PT4Bcs"}, {"id": "Ugzwlw-X_Mb5bLSrX0h4AaABAg", "text": "Nice", "author": "@Oko98l-oko98l", "like_count": 1, "published_at": "2025-10-09T20:55:05Z", "parent_id": null, "video_id": "vtkr-PT4Bcs"}, {"id": "Ugy7vKlUbD5N3D59Wch4AaABAg", "text": "Thank you Lord! You have no idea how much these videos help", "author": "@vanessanoheart", "like_count": 1, "published_at": "2026-03-03T17:16:21Z", "parent_id": null, "video_id": "LjRl4aEWnSo"}, {"id": "Ugy7vKlUbD5N3D59Wch4AaABAg.ATu2XHyfE4yATwf3CCoZ3c", "text": "Glad I could help, thank you for watching! \ud83d\ude4f", "author": "@PacificMotionVideo", "like_count": 1, "published_at": "2026-03-04T17:40:14Z", "parent_id": "Ugy7vKlUbD5N3D59Wch4AaABAg", "video_id": "LjRl4aEWnSo"}, {"id": "UgxrRvhijxyfxiQ5F2J4AaABAg", "text": "If you work from home try Thailand or Vietnam. You get a better apartment with an ocean view free daily cleaning service for $850/month", "author": "@hash_value", "like_count": 0, "published_at": "2026-04-05T13:02:57Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "text": "I hate the extraneous noises of apartment living. That''s why I bought a house.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:07:15Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "Ugx_GlGY8WFMvHYq15Z4AaABAg.AU9leOfMix5AUNRnLyJwxT", "text": "Good for you!!!! House privacy is the best tbh", "author": "@theamericanexplorer", "like_count": 0, "published_at": "2026-03-15T12:34:20Z", "parent_id": "Ugx_GlGY8WFMvHYq15Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "Ugx_SBkM3eJCHRl0F2l4AaABAg", "text": "Don\u2019t do it find another place another state", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:17:28Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg", "text": "Welcome to California. Welcome to Orange County the Irvine development company building huge compounds to shuffling people. That is their goal. Heavy taxes have a government and you will get nothing.", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:12:24Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgzskPqRyemqVIE5NnR4AaABAg.APFXOwGwUjaAU9qUUTiJCP", "text": "Lady, you don''t know what you''re talking about. \n1) Renters don''t pay property taxes on their apartment. \n2) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \n3) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \n4) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:49:27Z", "parent_id": "UgzskPqRyemqVIE5NnR4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgwBv8B2eGpjpqi2XNt4AaABAg", "text": "Just one big heaping mound of regret why would you don\u2019t do it?", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:10:58Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "text": "I hope you love taxes and heavy government. Enjoy", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:56Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgwwmASSGpLUE9uHz2Z4AaABAg.APFWlsu6i1DAU9rD00IBtZ", "text": "Lady, you don''t know what you''re talking about. \r\n1) California property tax rates are around 1.2% of assessed value. Assessed value starts at the purchase price but cannot increase more than 2% per year. \r\n2) The property tax rate in Orange County, CA, is only 1.011%. The ad-valorem property tax on my $1.2M home in Orange County, CA, is only $3500. \r\n3) I''m retired, with a gross income of $100,000, consisting of SS retirement benefits of about $25,000 and taxable investment income of about $75,000. \r\nCalifornia does not tax SS retirement benefits.  My California income tax is less than 2.7% of my gross income of $100,000.\r\n\r\nThe reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:55:48Z", "parent_id": "UgwwmASSGpLUE9uHz2Z4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg", "text": "Why would you buy a property in California?\ud83d\ude02 What an absolute joke", "author": "@johnhyland3084", "like_count": 0, "published_at": "2025-11-08T04:06:30Z", "parent_id": null, "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rTCJbL30", "text": "Lady, the reason California rents and home prices are high is because the demand for California housing is high.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T05:58:01Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}, {"id": "UgyCf_tuMyymtLshQjl4AaABAg.APFWigIS6dNAU9rnxx2Wqd", "text": "rockyrodes5 She doesn''t care about facts. She''s just a Republican with a hard need to vent against California, the 4th largest economy in the world.", "author": "@herrickinman9303", "like_count": 0, "published_at": "2026-03-10T06:00:59Z", "parent_id": "UgyCf_tuMyymtLshQjl4AaABAg", "video_id": "srt2NuMUmpk"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('woodbridge', '2026-04-22 04:03:17.150425', NULL, NULL, NULL, NULL, 0.064, NULL, NULL, 0.0, 62.0, 69.0, '["-8PTPy8HsmU", "HGAaEys0P1w", "CjuIZ2qdO5E", "84vX4334odw", "Th_4J195uAc", "U3HD51SY76Q", "2nWey4MCXW4"]', '[{"id": "UgzIynuECI4cDcXOyPZ4AaABAg", "text": "I live in Woodbridge and love it\ud83d\ude0a", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-17T00:13:38Z", "parent_id": null, "video_id": "HGAaEys0P1w"}, {"id": "UgxCms6_rQcf52rs4i94AaABAg", "text": "I spent middle and high school in this commie-munity. California is already wildly expensive and restrictive, but have your minds blown with HOA Karens and violation letters\u2026 \ud83e\udd26\ud83c\udffb\u200d\u2642\ufe0f", "author": "@SNAKEEATER1776", "like_count": 0, "published_at": "2025-04-22T12:54:48Z", "parent_id": null, "video_id": "HGAaEys0P1w"}, {"id": "UgzgXl3m3p8o7LhZqh14AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California?\ud83c\udf34\r\n\ud83d\udcf1Call or text:  949-285-1207\r\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\r\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa\r\n Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\r\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 1, "published_at": "2023-01-23T02:40:51Z", "parent_id": null, "video_id": "84vX4334odw"}, {"id": "Ugx-sSEW5lPJ2iG2UHR4AaABAg", "text": "In Woodbridge, we are representing owners in the leasing of a beautiful 4 bedroom, single family home at 70 Summerstone. Very nice upgrades, spacious backyard:  love living in Woodbridge by leasing 70 Summerstone!\n\nhttps://www.bruceclarkgroup.com/listing-detail/1170134714/70-Summerstone-Irvine-CA\n\n#woodbridgeirvine #bruceclark #realbroker #homeforlease", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-10-02T00:35:11Z", "parent_id": null, "video_id": "84vX4334odw"}, {"id": "UgzLnuQixuClgf6K8h14AaABAg", "text": "We love Irvine and Woodbridge has so many great things to offer residents. As of 10/1/2025, we have two properties available in Woodbridge:  43 Glenhurst, which is being offered for sale or for lease. A very nicely-upgraded 3 bedroom condo.\n\nhttps://www.bruceclarkgroup.com/listing-detail/1166293290/43-Glenhurst-Irvine-CA\n\n#IrvineCondo #condoforlease #irvinerealestate #woodbridge", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2025-10-02T00:32:09Z", "parent_id": null, "video_id": "84vX4334odw"}, {"id": "UgyzvNMSHouK_hW5Zv14AaABAg", "text": "I live in Woodbridge and I love it \u2764", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-17T17:45:54Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "Ugx2VECQkM-XCyCtoch4AaABAg", "text": "Really loving your videoss so amazing keep it up \ud83e\udd0d\ud83e\udd0d", "author": "@pankaj_suman", "like_count": 0, "published_at": "2024-01-19T08:01:59Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "UgyajVeqSVcNXNsjH0F4AaABAg", "text": "great editing btw", "author": "@lysssky2", "like_count": 0, "published_at": "2023-06-12T05:27:18Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "Ugw0Qh4EZBmLNeWJ9wN4AaABAg", "text": "the homes look older", "author": "@lysssky2", "like_count": 0, "published_at": "2023-06-12T05:25:57Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg", "text": "I love your driving tours!", "author": "@kaleimaile", "like_count": 1, "published_at": "2023-06-11T00:36:29Z", "parent_id": null, "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qo2CBl68Hg", "text": "Thanks! We''re doing a lot more!", "author": "@LivinginOrangeCounty", "like_count": 1, "published_at": "2023-06-11T04:22:15Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qo4WnulXg5", "text": "@LivinginOrangeCounty , Whoohoo!  While you guys talk about the various streets, I try to figure where you\u2019re at from the maps on my phone. Lol!  Do a driving tour in FV or HB & I will know where you are driving to in the video! \ud83d\ude02\ud83e\udd23\ud83d\ude02", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-06-11T04:42:32Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qp2b_7FWhE", "text": "@kaleimaile Lol. We are definitely planning a driving tour of FV and HB. It''s just been so overcast we''re waiting for the skies to clear, lol.", "author": "@LivinginOrangeCounty", "like_count": 1, "published_at": "2023-06-11T13:45:05Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qp42lTvhQ6", "text": "@LivinginOrangeCounty , hehe. Thanks. I know. It\u2019s been overcast, but I love the weather for running. I am not looking forward to having a hot summer. \ud83e\udd75\ud83e\udd75\ud83e\udd75", "author": "@kaleimaile", "like_count": 0, "published_at": "2023-06-11T13:57:41Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzCV0FQw3SAYijlpY54AaABAg.9qndM_myAZ-9qpwhEfOimk", "text": "@56strine , oh, but the \u2018runner\u2019s high\u2019 is why we run long distance. Lol!", "author": "@kaleimaile", "like_count": 1, "published_at": "2023-06-11T22:03:56Z", "parent_id": "UgzCV0FQw3SAYijlpY54AaABAg", "video_id": "Th_4J195uAc"}, {"id": "UgzXiGW3h07I8XRT1Xh4AaABAg", "text": "I live in Woodbridge and I LOVE it \ud83d\ude0a", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-16T23:46:23Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgxZkA8XysvS4sVEyj54AaABAg", "text": "I grew up in the houses along the lake in the beginning of the video.  I forgot if it was either north or south lake. It was in the 80s. Went to stonecreek elementary.  It was such a fun time.  I miss it. \ud83d\ude22", "author": "@SPChef1981", "like_count": 1, "published_at": "2022-11-22T15:27:51Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgwjLtfwZW1QUE-SI8h4AaABAg", "text": "Thanks for the video.  I grew up in Woodbridge. Went to Eastshore elementary and lake side middle school. Haven''t seen cali in a minute thanks again.", "author": "@DaProblem850", "like_count": 1, "published_at": "2022-04-10T20:59:20Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgzXMkop908aVOnMKLl4AaABAg", "text": "Do a video on Great Park Neighborhoods", "author": "@kasufert", "like_count": 0, "published_at": "2022-02-24T07:15:16Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgzXMkop908aVOnMKLl4AaABAg.9YoznS30RIq9YpQntJtNxs", "text": "Wait just realized you already have one on it lol", "author": "@kasufert", "like_count": 0, "published_at": "2022-02-24T11:20:00Z", "parent_id": "UgzXMkop908aVOnMKLl4AaABAg", "video_id": "U3HD51SY76Q"}, {"id": "Ugxv6piQI6LLvHU_HRV4AaABAg", "text": "Nice content! The theme song from the OC plays in my head every time I see y''all. Maybe it''s a sign?", "author": "@TheKevinNewsom", "like_count": 1, "published_at": "2021-12-25T03:21:59Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgxoygHISmWeRBUzLU14AaABAg", "text": "We bought our 4 bedroom home down here in Laguna Hills back in 2009 for 500K and the price has doubled now. Best place to live with no HOA or Mello Roos tax.", "author": "@LagunaRider1961", "like_count": 2, "published_at": "2021-12-24T20:16:31Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "UgwIEDS_I4vkR8d7D1F4AaABAg", "text": "Great videos! Love your content! I just think it gets too chilly in the winter near the beach especially how it is more windy with the cold sea breeze. During summer it''s perfect to me though. I prefer inland during winter due to higher warmer daytime Temps compared to the daytime Temps near the beach areas during winter or cold months.", "author": "@GregoryMorales-uo6ze", "like_count": 0, "published_at": "2021-12-24T00:59:16Z", "parent_id": null, "video_id": "U3HD51SY76Q"}, {"id": "Ugw6UZCj9CyxpiJ6ew94AaABAg", "text": "\ud83e\udd14Thinking of moving to or selling your home in Irvine California?\ud83c\udf34\r\n\ud83d\udcf1Call or text:  949-285-1207\r\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\r\n\ud83d\udcc5Zoom:  http://bit.ly/3ZeNnEa\r\n Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\r\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-01-20T02:19:27Z", "parent_id": null, "video_id": "2nWey4MCXW4"}, {"id": "Ugw6UZCj9CyxpiJ6ew94AaABAg.9l5BGaKaWN8ADN6xqYs8zt", "text": "How much rent for 1 bedroom apartment / condo ?", "author": "@mirashahh789", "like_count": 0, "published_at": "2025-01-16T20:38:34Z", "parent_id": "Ugw6UZCj9CyxpiJ6ew94AaABAg", "video_id": "2nWey4MCXW4"}, {"id": "UgyJPDVuHCU5_EuN9Mh4AaABAg", "text": "I live in Woodbridge and I love it \ud83d\ude0a", "author": "@DrJenniferY", "like_count": 0, "published_at": "2025-12-17T19:50:59Z", "parent_id": null, "video_id": "2nWey4MCXW4"}, {"id": "UgyIOY_28GJZsCehMAt4AaABAg", "text": "Please check your mail, I''ve sent a message about your YouTube Channel", "author": "@dhrubaofficial8211", "like_count": 0, "published_at": "2023-01-22T19:28:59Z", "parent_id": null, "video_id": "2nWey4MCXW4"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('university-town-center', '2026-04-22 04:04:18.830486', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0.0, 68.0, 75.0, '["ReuCsIZgXkI", "kOOtA8Snjx0", "-H1L4lrwlso", "a-erhfkqTi4", "2Z_NzK00lSg", "NitCpMg3RTE", "Nz2VCPxuVes", "wDzbxwCvwnA", "3lep-Ui5FxE"]', '[{"id": "Ugy-BjL9VuIZOWwUEl14AaABAg", "text": "\u7559\u5b66\u751f\u306fArroyo Vista\u304c\u5927\u534a\u3068\u805e\u304d\u307e\u3057\u305f\u3002\u305d\u3053\u4ee5\u5916\u306e\u5bee\u306b\u7559\u5b66\u751f\u306f\u4f4f\u3093\u3067\u3044\u307e\u3059\u304b\uff1f\u307e\u305f\u3001\u4ed6\u306e\u5bee\u3060\u3068\u7559\u5b66\u751f\u304c\u5c11\u306a\u304f\u3066\u8f9b\u3044\u601d\u3044\u3092\u3059\u308b\u3053\u3068\u306f\u3042\u308a\u307e\u3059\u304b\uff1f", "author": "@\u305f\u3053-r9x1q", "like_count": 0, "published_at": "2024-07-28T16:34:54Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugwgx2WHOSrfo0MT0N94AaABAg", "text": "Camino Del Sol is the safer place to live? :-/   Why isn''t the other place safe too?", "author": "@lisan1823", "like_count": 0, "published_at": "2023-09-21T06:03:49Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugwgx2WHOSrfo0MT0N94AaABAg.9uuruM-AYdh9uwFVrcJXPm", "text": "Hi there, Irvine is generally pretty safe! Camino Del Sol is a smaller community and is closer to campus/other housing than Vista Del Campo and Vista Del Campo Norte, so there is more traffic and events happening regularly. Vista Del Campo is on the outskirts of campus so there is minimal traffic/activity happening in that area but some of my friends who lived in that area enjoyed it. What was sometimes challenging was how far it was from campus.", "author": "@a2fIrvine", "like_count": 2, "published_at": "2023-09-21T18:58:02Z", "parent_id": "Ugwgx2WHOSrfo0MT0N94AaABAg", "video_id": "-H1L4lrwlso"}, {"id": "Ugwlj3KmqBbSiogrvXh4AaABAg", "text": "I actually live near here and go to uni high school I walk around up I from time to time near the Main Street so I know the area pretty well", "author": "@strangerthingsfan4521", "like_count": 0, "published_at": "2022-05-24T02:29:51Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugy-3Enzl44diTnMgBh4AaABAg", "text": "I\u2019m not sure if you guys answer anymore but in terms of cost do you guys recommend ACC or UTC? I\u2019m going to be a transfer soon and this whole housing process have been giving me headaches. Also do any of the options allow non-students to temporarily live with you for a while like for a visit?", "author": "@user-kx1cy3re6k", "like_count": 3, "published_at": "2022-05-20T14:23:34Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "Ugy-3Enzl44diTnMgBh4AaABAg.9bFcNn0SyB79bFcfE9gMuK", "text": "Also do I have to have a roommate or is there options otherwise?", "author": "@user-kx1cy3re6k", "like_count": 1, "published_at": "2022-05-20T14:26:05Z", "parent_id": "Ugy-3Enzl44diTnMgBh4AaABAg", "video_id": "-H1L4lrwlso"}, {"id": "UgxjJwZyUU_4VNxY5vF4AaABAg", "text": "Hi , I am Namgyal and lives in New York , this summer I got accepted into a research program at UCI and I am looking for a room for a 10 weeks . So any leads on such will be highly appreciated. Thank you", "author": "@namgyaldolma2098", "like_count": 0, "published_at": "2022-03-31T12:58:01Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "UgxjJwZyUU_4VNxY5vF4AaABAg.9_EiqQreOsG9asZnwV-har", "text": "One pointer is the people subleasing their rooms for summer, for the ACC apartments, since the lease is 12 months long and not everyone is staying for the summer. Another pointer would be summer housing at the various on-campus housing communities, including dorms, though I''m not sure on the specifics", "author": "@_DeathDreams_", "like_count": 0, "published_at": "2022-05-11T06:10:33Z", "parent_id": "UgxjJwZyUU_4VNxY5vF4AaABAg", "video_id": "-H1L4lrwlso"}, {"id": "UgxRKb6iTwavcDuRqCR4AaABAg", "text": "Very good and funny videos bring a great sense of entertainment!", "author": "@PhuongNguyen-se7xd", "like_count": 0, "published_at": "2021-10-25T08:49:11Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "UgyGVkU9iMq3hM_ZBLN4AaABAg", "text": "Most nicest?!?!?!? No!! No!!! Noooooooooo. Lol", "author": "@ellenlewitt", "like_count": 0, "published_at": "2021-08-12T22:07:49Z", "parent_id": null, "video_id": "-H1L4lrwlso"}, {"id": "UgxqPrnMXEbOW_OEnC54AaABAg", "text": "Brought and PAID for by UCI. \ud83d\ude02", "author": "@maximai", "like_count": 0, "published_at": "2026-04-03T04:28:49Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "Ugy4IXepHpvfztTf5uN4AaABAg", "text": "UCI is the biggest commuter school \u2620\ufe0f", "author": "@electrongaming123", "like_count": 3, "published_at": "2025-09-29T18:43:44Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "Ugwl2fYNyqduKPBjcJp4AaABAg", "text": "UCI does not have a social life \ud83d\ude05", "author": "@Lakan-dula", "like_count": 23, "published_at": "2025-09-15T15:42:05Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgwYPMQN_FTzqwmBF8h4AaABAg", "text": "I got into UCI :)", "author": "@mr.fishstick_yt9955", "like_count": 5, "published_at": "2024-03-22T04:19:33Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgxQBgFHtWFpyiW_FB54AaABAg", "text": "UCI \u2764", "author": "@sunflowersarles1sun827", "like_count": 2, "published_at": "2023-10-13T01:38:47Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgyxF3ZDGljG0FvytDl4AaABAg", "text": "Did you get into one of them ?", "author": "@doucegraciela5555", "like_count": 1, "published_at": "2022-10-09T05:28:37Z", "parent_id": null, "video_id": "a-erhfkqTi4"}, {"id": "UgzCBXPqsZIdvSshzi54AaABAg", "text": "glamour piece. useless.", "author": "@forwags", "like_count": 0, "published_at": "2026-04-08T19:16:27Z", "parent_id": null, "video_id": "2Z_NzK00lSg"}, {"id": "UgxEfq1naB6XwvVgDF94AaABAg", "text": "Comment on which campus you''d like to see next", "author": "@MathTeddyLofi", "like_count": 0, "published_at": "2023-04-13T02:16:16Z", "parent_id": null, "video_id": "2Z_NzK00lSg"}, {"id": "UgwCvDsgAh-Y4b7Zcz14AaABAg", "text": "We finally get an Irvine video", "author": "@melvinchen7051", "like_count": 1, "published_at": "2023-04-12T17:16:49Z", "parent_id": null, "video_id": "2Z_NzK00lSg"}]', 0.33, '{"sources": {"zori_csv": false, "overpass_grocery": false, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('portola-springs', '2026-04-22 04:06:41.779587', NULL, NULL, NULL, NULL, 0.0, NULL, NULL, 0.0, 75.0, 82.0, '["1oAzwDwETJk", "zu5GyEK_SSo", "xtVLrakGkWs", "DPqMp1Z-nyQ", "3Y1n9pb70NM", "aV-Kx0OghxQ"]', '[{"id": "Ugy5bNUuAfpQD22SxHJ4AaABAg", "text": "Check out", "author": "@carinatruong6446", "like_count": 0, "published_at": "2026-03-19T02:33:29Z", "parent_id": null, "video_id": "zu5GyEK_SSo"}, {"id": "Ugz12qfDeAg9V_NLyQR4AaABAg", "text": "======\r\nContact us: \ud83d\udc47\ud83d\udc47\ud83d\udc47 Full Channel: \ud83d\udc49\ud83d\udc49\ud83d\udc49: https://bit.ly/3NXecX3\r\n=======\r\n\ud83d\udcf1Call or text:  949-285-1207\r\n\ud83d\udce7Email:  info@livinginirvinecalifornia.com\r\n\ud83d\udcc5Schedule a Zoom Call So We Can Meet \"In-Person\":\r\nhttps://calendly.com/living-in-irvine-ca/30min?month=2022-12\r\n=======", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2022-12-29T17:08:01Z", "parent_id": null, "video_id": "xtVLrakGkWs"}, {"id": "Ugy1QrjKTflNtl_Fw2d4AaABAg", "text": "Horribly designed house; the laundry area next to bedrooms and upstairs, good luck when you have leakage problems.", "author": "@mistapropa408", "like_count": 1, "published_at": "2023-09-28T05:51:20Z", "parent_id": null, "video_id": "xtVLrakGkWs"}, {"id": "Ugy1QrjKTflNtl_Fw2d4AaABAg.9vBs1x5xTnD9wGf69dtMjJ", "text": "For many, having the laundry upstairs next to the bedrooms is preferable, especially those with kids. Leaks never good! (Apologies for the delay in replying.)", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-10-24T23:05:54Z", "parent_id": "Ugy1QrjKTflNtl_Fw2d4AaABAg", "video_id": "xtVLrakGkWs"}, {"id": "UgwQ509oXhdHQ_MsJ2p4AaABAg", "text": "Before the year 2030.", "author": "@armandoenriquez1104", "like_count": 1, "published_at": "2023-01-07T15:22:40Z", "parent_id": null, "video_id": "xtVLrakGkWs"}, {"id": "UgwQ509oXhdHQ_MsJ2p4AaABAg.9ka6Zf1hN919kaRvcwkhod", "text": "Hi Armando, thanks for watching our videos! So do you foresee a big shift reported in the next Census?", "author": "@LivinginIrvineCalifornia", "like_count": 0, "published_at": "2023-01-07T18:29:19Z", "parent_id": "UgwQ509oXhdHQ_MsJ2p4AaABAg", "video_id": "xtVLrakGkWs"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
INSERT INTO community_metrics (community_id, updated_at, median_rent, rent_2b2b, rent_1b1b, avg_sqft, grocery_density_per_km2, crime_rate_per_100k, rent_trend_12m_pct, night_activity_index, noise_avg_db, noise_p90_db, youtube_video_ids, youtube_comments, overall_confidence, details_json) VALUES ('quail-hill', '2026-04-22 04:07:49.255655', NULL, NULL, NULL, NULL, 0.052, NULL, NULL, 0.0, 68.0, 75.0, '["srvzTpHOj3w", "WSjnL6rSyHw", "GJOu82_tykg", "sNvRIE9bfXE", "OMj6i1gggHI", "wfUwD9EJbgE", "SRTdUq4VlCY"]', '[{"id": "Ugy5SjJw5j246wihitd4AaABAg", "text": "VEry good", "author": "@SaidulCreative-j1r", "like_count": 1, "published_at": "2025-07-12T20:45:29Z", "parent_id": null, "video_id": "srvzTpHOj3w"}, {"id": "Ugxq3AShsDcgstBGQ1N4AaABAg", "text": "u want a shoutout? :D", "author": "@ava7342", "like_count": 0, "published_at": "2020-08-25T17:14:18Z", "parent_id": null, "video_id": "sNvRIE9bfXE"}, {"id": "UgyGtrnSNysZ3WcxN1Z4AaABAg", "text": "I appreciate the Resilience of property prices in irvine so much", "author": "@alexanderschwarm7755", "like_count": 0, "published_at": "2024-02-11T09:15:31Z", "parent_id": null, "video_id": "wfUwD9EJbgE"}, {"id": "Ugx04OTWFb4eYHKhTXZ4AaABAg", "text": "New construction tours model home and existing homes tours? updates!? Boots on ground visit new builds see available model & spec inventory! Master planned boots on site tours!?\ud83e\udde4\ud83d\ude42\ud83d\udc4d\ud83d\udeb5\ud83c\udffb\u200d\u2642\ufe0f", "author": "@michaelsyufy7733", "like_count": 0, "published_at": "2024-02-10T19:48:06Z", "parent_id": null, "video_id": "wfUwD9EJbgE"}, {"id": "UgyYrSDj5pqvCsm8OU54AaABAg", "text": "I am also an original owner at Quail Hill since 2005.  My favorite features are the pools.  I swim laps multiple times a week all year long!   The trial to Laguna Beach is a close second!", "author": "@chrisknotz1984", "like_count": 0, "published_at": "2025-08-24T17:25:49Z", "parent_id": null, "video_id": "SRTdUq4VlCY"}, {"id": "UgyYrSDj5pqvCsm8OU54AaABAg.AMDFmaXFmzyANK0aOYfF_M", "text": "Thanks for sharing! The pools are a great amenity, and the trail to the beach is very popular too!", "author": "@swardstromgroup", "like_count": 0, "published_at": "2025-09-21T04:59:10Z", "parent_id": "UgyYrSDj5pqvCsm8OU54AaABAg", "video_id": "SRTdUq4VlCY"}, {"id": "UgwD6fnbtKmSzwZgmFR4AaABAg", "text": "If you have been to Quail Hill, let us know your favorite feature of this amazing community in the COMMENTS below! \ud83d\ude0a\n\nFor more information about Quail Hill, visit our community website - click here: https://LivingQuailHill.com\nor email, call or text :\nEMAIL: Doug@SwardstromGroup.com or Rachel@SwardstromGroup.com\nPHONE: (949) 302-4883", "author": "@swardstromgroup", "like_count": 3, "published_at": "2023-09-13T22:33:56Z", "parent_id": null, "video_id": "SRTdUq4VlCY"}]', 0.5, '{"sources": {"zori_csv": false, "overpass_grocery": true, "overpass_night_activity": false, "overpass_noise": true, "irvine_crime": false, "irvine_crime_source": "missing:missing_api_key", "crime_api": false, "crime_api_source": "missing:missing_api_key", "youtube_video": true, "commute_minutes": null, "viirs_night_activity": false, "night_activity_source": "cached"}}');
