INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('6ddfe446-27b5-476d-a291-bec6a74a0936', 'irvine-spectrum', 'youtube', 'Ugz7l40YP-WOxEVmDqF4AaABAg', NULL, '2026-04-16 21:06:47', NULL, 'My son is 17, Northwood high school. GPA over 3.5. He''s had a good high school experience. He''s not taking all AP classes and not getting tudors. Yes, if you want over a 4.0 there''s more work involved. But going to school in Irvine doesn''t require crazy amounts of work and tudors if you don''t want to go to an Ivy league school. You can still get into fine schools, haha.', NULL, '@ChrisRivera-lz3lo', 0.0);
