INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('ab66fb86-c43d-4b14-8081-c0434c86f7a3', 'irvine-spectrum', 'youtube', 'Ugwep9dq5yI_FgL7TkV4AaABAg', NULL, '2026-02-15 07:36:33', NULL, 'A family I am close to with two young children moved from Pasadena to Irvine for work. They liked Pasadena, but they have grown to like Irvine. Their rent is higher in Irvine, but they are in a nice place that is not 100 years old.', NULL, '@prrosenkrantz', 0.0);
