INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('40502d21-8694-4af8-97ae-693a7b6c477e', 'woodbridge', 'youtube', 'UgxCms6_rQcf52rs4i94AaABAg', NULL, '2025-04-22 12:54:48', NULL, 'I spent middle and high school in this commie-munity. California is already wildly expensive and restrictive, but have your minds blown with HOA Karens and violation letters… 🤦🏻‍♂️', NULL, '@SNAKEEATER1776', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('504938bb-c476-4a1d-8632-e7604ec27b2a', 'university-town-center', 'youtube', 'Ugwgx2WHOSrfo0MT0N94AaABAg', NULL, '2023-09-21 06:03:49', NULL, 'Camino Del Sol is the safer place to live? :-/   Why isn''t the other place safe too?', NULL, '@lisan1823', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('7a2bbf1c-8f12-4b12-a0e6-f00b202fb498', 'irvine-spectrum', 'youtube', 'Ugwre5ef-NVNhqbLa1N4AaABAg', NULL, '2025-11-19 15:58:27', NULL, 'It takes time to understand Irvine.  But once you live there after a year you realize why it was built the way it is with shopping centers facing inward to prevent crime, pedestrians, and homeless.  And how it was built with 3 to 4 lane throughways to improve traffic and minimize slowing by moving entrances to shopping centers to inner streets.  And of course the master planned communities designed to mix apartments, condos and SFHs to provide diversity within each village.  Then there’s the massive amount of land dedicated to parks and biking.  Irvine is intentionally the anti-city designed to improve the quality of family life.', NULL, '@ap774', 0.0);
INSERT INTO review_post (post_id, community_id, platform, external_id, url, posted_at, title, body_text, parent_id, author_name, like_count) VALUES ('69c6c303-2ec7-4000-9453-23dd05ff612d', 'irvine-spectrum', 'youtube', 'UgybuXEX8V9EEdCu6IV4AaABAg', NULL, '2025-08-25 23:26:09', NULL, 'Irvine is so over built and the traffic is horrible. Most of the shopping centers are so crowded it can be hard to find a parking spot. It was a great place 45 years ago but no more!', NULL, '@MikeB-in1nd', 2.0);
